+
+    if (in == NULL) {
+        return BASE64_ERROR_DATA_IN;
+    }
+
+    if (base64_in_size == 0) {
+        *data_out_size = 0;
+        return BASE64_SUCCESS;
+    }
+
+    if (base64_in_size < 4) {
+        *data_out_size = required_size;
+        return BASE64_ERROR_DATA_IN_SIZE;
+    }
+
+    if (*data_out_size < required_size) {
+        *data_out_size = required_size;
+        return BASE64_ERROR_BUFFER_OUT_SIZE;
+    }
+
