+            if (code == BASE64_NOT_DEFINED) {
+                continue;
+            }
+            if (code == BASE64_EQUALS) {
+                padding++;
+                codes[pos++] = 0;
+            } else {
+                codes[pos++] = code;
+            }
+        }
+
+        if (pos == 0) {
+            break;
+        }
+
+        int orig_pos = pos;
+
+        while (pos < 4) {
+            codes[pos++] = 0;
+        }
+
+        decode_four_codes(out + *data_out_size, codes);
+
+        *data_out_size += padding ? (3 - padding) : (orig_pos - 1);
+    }
+
+    return BASE64_SUCCESS;
