--- sys/net/ble/bluetil/bluetil_addr/bluetil_addr.c
+++ sys/net/ble/bluetil/bluetil_addr/bluetil_addr.c
@@ -90,7 +90,51 @@

 void bluetil_addr_ipv6_l2ll_sprint(char *out, const uint8_t *addr)
 {
-    /* MASKED - implement this function */
+    assert(out);
+    assert(addr);
+
+    /* Build the IID (modified EUI-64) from the BLE address.
+     * Insert 0xFFFE between byte 2 and 3 of the 48-bit address.
+     * For BLE, the U/L bit is NOT flipped. */
+    uint8_t iid[8] = {
+        addr[0], addr[1], addr[2],
+        0xff, 0xfe,
+        addr[3], addr[4], addr[5]
+    };
+
+    /* Format as IPv6 link-local address per RFC 5952:
+     * lowercase hex, leading zero suppression, :: for zero compression */
+    char *pos = out;
+
+    pos[0] = 'f'; pos[1] = 'e'; pos[2] = '8'; pos[3] = '0';
+    pos[4] = ':'; pos[5] = ':';
+    pos += 6;
+
+    static const char HEX[] = "0123456789abcdef";
+
+    for (unsigned w = 0; w < 4; w++) {
+        if (w > 0) {
+            *pos++ = ':';
+        }
+        uint8_t hi = iid[w * 2];
+        uint8_t lo = iid[w * 2 + 1];
+
+        if (hi & 0xf0) {
+            *pos++ = HEX[hi >> 4];
+            *pos++ = HEX[hi & 0x0f];
+            *pos++ = HEX[lo >> 4];
+        }
+        else if (hi & 0x0f) {
+            *pos++ = HEX[hi & 0x0f];
+            *pos++ = HEX[lo >> 4];
+        }
+        else if (lo & 0xf0) {
+            *pos++ = HEX[lo >> 4];
+        }
+        *pos++ = HEX[lo & 0x0f];
+    }
+
+    *pos = '\0';
 }

