+    if (ecc_key.type != ASN1_TYPE_SEQUENCE) {
+        DEBUG("credman: the ECC private key should be contained in an ASN.1 SEQUENCE\n");
+        return CREDMAN_INVALID;
+    }
+
+    /* point to version */
+    asn1_tree *node = ecc_key.child;
+    if (!node || node->type != ASN1_TYPE_INTEGER) {
+        DEBUG("credman: invalid ECC private key version\n");
+        return CREDMAN_INVALID;
+    }
+
+    /* point to privateKey */
+    node = node->next;
+    if (!node || node->type != ASN1_TYPE_OCTET_STRING || !node->data || !node->length) {
+        DEBUG("credman: no ECC private key found\n");
+        return CREDMAN_INVALID;
+    }
+
+    cred->type = CREDMAN_TYPE_ECDSA;
+    cred->params.ecdsa.private_key = node->data;
+
+    /* clear public key in case there's no optional publicKey */
+    cred->params.ecdsa.public_key.x = NULL;
+    cred->params.ecdsa.public_key.y = NULL;
+
+    /* point to optional parameters or publicKey */
+    node = node->next;
+
+    /* skip optional parameters [0] if present */
+    if (node && node->type == ASN1_CONTEXT_TAG(0)) {
+        node = node->next;
+    }
+
+    /* check for optional publicKey [1] */
+    if (node && node->type == ASN1_CONTEXT_TAG(1) && node->child) {
+        return _parse_ecc_point(node->child, &cred->params.ecdsa.public_key.x,
+                                &cred->params.ecdsa.public_key.y);
+    }
+
+    return CREDMAN_OK;
