+    /* look for optional publicKey [1] */
+    asn1_tree *pub_key_node = node->next;
+    while (pub_key_node && pub_key_node->type != ASN1_CONTEXT_TAG(1)) {
+        pub_key_node = pub_key_node->next;
+    }
+
+    /* delegate to ECPrivateKey parser for the inner key */
+    int ret = credman_load_private_ecc_key(node->data, node->length, cred);
+    if (ret != CREDMAN_OK) {
+        return ret;
+    }
+
+    /* if publicKey is present at the PKCS#8 level, it takes precedence */
+    if (pub_key_node) {
+        return _parse_ecc_point(pub_key_node->child, &cred->params.ecdsa.public_key.x,
+                                &cred->params.ecdsa.public_key.y);
+    }
+
+    return CREDMAN_OK;
