+    const uint8_t *bufpos = buf + sizeof(dns_hdr_t);
+    const uint8_t *buflim = buf + len;
+
+    uint16_t qdcount = ntohs(hdr->qdcount);
+    uint16_t ancount = ntohs(hdr->ancount);
