+        bufpos += res;
+        if (bufpos + RR_TYPE_LENGTH + RR_CLASS_LENGTH > buflim) {
+            return -EBADMSG;
+        }
+        bufpos += RR_TYPE_LENGTH + RR_CLASS_LENGTH;
+    }
