+        rr_ttl = ntohl(rr_ttl);
+        bufpos += RR_TTL_LENGTH;
+
+        uint16_t rdlength = ntohs(_get_short(bufpos));
+        bufpos += RR_RDLENGTH_LENGTH;
+
+        if (bufpos + rdlength > buflim) {
+            return -EBADMSG;
+        }
+
+        if (family == AF_UNSPEC) {
+            if (type == DNS_TYPE_AAAA && rdlength == 16) {
+                found_addr = bufpos;
+                found_ttl = rr_ttl;
+                found_len = 16;
+                break;
+            }
+            if (type == DNS_TYPE_A && rdlength == 4 && found_len == 0) {
+                found_addr = bufpos;
+                found_ttl = rr_ttl;
+                found_len = 4;
+            }
+        }
+        else if (family == AF_INET && type == DNS_TYPE_A && rdlength == 4) {
+            found_addr = bufpos;
+            found_ttl = rr_ttl;
+            found_len = 4;
+            break;
+        }
+        else if (family == AF_INET6 && type == DNS_TYPE_AAAA && rdlength == 16) {
+            found_addr = bufpos;
+            found_ttl = rr_ttl;
+            found_len = 16;
+            break;
+        }
+
+        bufpos += rdlength;
+    }
+
+    if (found_len == 0) {
