+        (free_block->size >= extra_needed)) {
+        if (sizeof(_unused_t) > (free_block->size - extra_needed)) {
+            if (prev == NULL) {
+                _first_unused = free_block->next;
+            }
+            else {
+                prev->next = free_block->next;
+            }
+        }
+        else {
+            _unused_t *new_free = (_unused_t *)((uintptr_t)free_block + extra_needed);
+            if (prev == NULL) {
+                _first_unused = new_free;
+            }
+            else {
