+    /* Allocate new region, copy, free old */
+    void *new_data = _pktbuf_alloc(size);
+    if (new_data == NULL) {
+        mutex_unlock(&gnrc_pktbuf_mutex);
+        return ENOMEM;
+    }
+    memcpy(new_data, pkt->data, pkt->size);
+    gnrc_pktbuf_free_internal(pkt->data, pkt->size);
+    pkt->data = new_data;
+    pkt->size = size;
+    mutex_unlock(&gnrc_pktbuf_mutex);
