+    uintptr_t addr = (uintptr_t)stack;
+    unsigned word_align = sizeof(uintptr_t);
+    if (addr & (word_align - 1)) {
+        unsigned offset = word_align - (addr & (word_align - 1));
+        addr += offset;
+        stacksize -= (int)offset;
+    }
+
+    if (stacksize < (int)sizeof(thread_t)) {
+        return -EINVAL;
+    }
+
+    unsigned state = irq_disable();
+
+    if (sched_num_threads >= MAXTHREADS) {
+        irq_restore(state);
+        return -EOVERFLOW;
+    }
+
+    /* find a free PID */
+    kernel_pid_t pid = KERNEL_PID_FIRST;
+    while (pid <= KERNEL_PID_LAST && sched_threads[pid]) {
+        pid++;
+    }
+
+    if (pid > KERNEL_PID_LAST) {
+        irq_restore(state);
+        return -EOVERFLOW;
+    }
+
+    thread_t *thread = (thread_t *)addr;
+
+    /* the actual (usable) stack begins after the thread control block */
+    char *real_stack = (char *)(addr + sizeof(thread_t));
+    int real_stacksize = stacksize - (int)sizeof(thread_t);
+
+#if defined(DEVELHELP) || IS_ACTIVE(SCHED_TEST_STACK)
+    if (!(flags & THREAD_CREATE_NO_STACKTEST)) {
+        /* fill stack with canary pattern: each word holds its own address */
+        uintptr_t *p = (uintptr_t *)(uintptr_t)real_stack;
+        uintptr_t *end = (uintptr_t *)((uintptr_t)real_stack + (uintptr_t)real_stacksize);
+        while (p < end) {
+            *p = (uintptr_t)p;
+            p++;
+        }
+    }
+#endif
+
+    thread->sp = thread_stack_init(function, arg, real_stack, real_stacksize);
+    thread->status = STATUS_STOPPED;
+    thread->priority = priority;
+    thread->pid = pid;
+    thread->rq_entry.next = NULL;
+
+#if defined(MODULE_CORE_MSG)
+    thread->msg_waiters.next = NULL;
+    thread->msg_array = NULL;
+#endif
+
+#if defined(DEVELHELP) || IS_ACTIVE(SCHED_TEST_STACK) \
+    || defined(MODULE_MPU_STACK_GUARD)
+    thread->stack_start = real_stack;
+#endif
+
+#if defined(DEVELHELP)
+    thread->stack_size = real_stacksize;
+#endif
+
+#if defined(CONFIG_THREAD_NAMES)
+    thread->name = name;
+#else
+    (void)name;
+#endif
+
+#ifdef PICOLIBC_TLS
+    thread->tls = _tls_new();
+#endif
+
+    sched_threads[pid] = thread;
+    sched_num_threads++;
+
+    if (flags & THREAD_CREATE_SLEEPING) {
+        sched_set_status(thread, STATUS_SLEEPING);
+    }
+    else {
+        sched_set_status(thread, STATUS_PENDING);
+    }
