--- sys/net/application_layer/unicoap/options.c
+++ sys/net/application_layer/unicoap/options.c
@@ -588,7 +588,76 @@
 int unicoap_options_add(unicoap_options_t* options, unicoap_option_number_t number,
                         const uint8_t* value, size_t value_size)
 {
-    /* MASKED - implement this function */
+    unicoap_option_entry_t* opts = options->entries;
+    assert(value_size <= UNICOAP_UINT_MAX);
+    assert(opts->data);
+
+    size_t count = options->option_count;
+
+    /* Find insertion index: first option with number > new option's number */
+    size_t i = 0;
+    while (i < count && opts[i].number <= number) {
+        i++;
+    }
+
+    if (count >= CONFIG_UNICOAP_OPTIONS_MAX) {
+        return -ENOBUFS;
+    }
+
+    uint16_t delta = (i > 0) ? (number - opts[i - 1].number) : number;
+    ssize_t option_size = _option_size(delta, value_size);
+    if (option_size < 0) {
+        return (int)option_size;
+    }
+
+    bool has_successor = (i < count);
+    ssize_t total_data_diff = option_size;
+    uint8_t length_nibble = 0;
+    uint16_t successor_new_delta = 0;
+
+    if (has_successor) {
+        length_nibble = DECODE_LENGTH_NIBBLE(*opts[i].data);
+        successor_new_delta = opts[i].number - number;
+        ssize_t successor_diff = _option_size_diff(successor_new_delta,
+                                                    DECODE_DELTA_NIBBLE(*opts[i].data));
+        total_data_diff += successor_diff;
+    }
+
+    if (options->storage_size + total_data_diff > options->storage_capacity) {
+        return -ENOBUFS;
+    }
+
+    /* Shift entries to make room in the lookup array.
+     * This duplicates the successor entry at indices i and i+1. */
+    _shift_option_entries(options, i, 1);
+
+    if (has_successor) {
+        /* Shift data starting from the successor (now at index i + 1).
+         * After this, opts[i].data still points to the original successor position,
+         * which now has total_data_diff free bytes before the shifted successor. */
+        _shift_options(options, i + 1, total_data_diff);
+
+        uint8_t* dest = opts[i].data;
+        _write_option(&dest, delta, value, value_size);
+        opts[i].number = number;
+        opts[i].size = option_size;
+
+        /* Fix successor's head: its delta changed, length nibble stays the same */
+        dest = opts[i + 1].data;
+        _write_head_partial(&dest, successor_new_delta, length_nibble);
+    }
+    else {
+        /* Append at end of storage buffer */
+        opts[i].data = opts[0].data + options->storage_size;
+        options->storage_size += option_size;
+
+        uint8_t* dest = opts[i].data;
+        _write_option(&dest, delta, value, value_size);
+        opts[i].number = number;
+        opts[i].size = option_size;
+    }
+
+    return 0;
 }

