+        const char *seg_end = _strchrb(p, query_end, '&');
+        if (!seg_end) {
+            seg_end = query_end;
+        }
+
+        /* empty segment (e.g. leading/trailing '&' or consecutive '&') */
+        if (p == seg_end) {
+            return -1;
+        }
+
+        if (count >= params_len) {
+            return -2;
+        }
+
+        const char *eq = _strchrb(p, seg_end, '=');
+
+        if (eq == NULL) {
+            params[count].name = p;
+            params[count].name_len = seg_end - p;
+        }
+        else {
+            /* name must not be empty */
+            if (eq == p) {
+                return -1;
+            }
+
+            params[count].name = p;
+            params[count].name_len = eq - p;
+            params[count].value = eq + 1;
+            params[count].value_len = seg_end - (eq + 1);
+        }
+
+        count++;
+
+        /* advance past '&' separator if present */
+        p = seg_end;
+        if (p < query_end && *p == '&') {
+            p++;
+        }
+    }
+
+    return count;
+}

