--- sys/vfs/vfs.c
+++ sys/vfs/vfs.c
@@ -914,7 +914,69 @@

 int vfs_normalize_path(char *buf, const char *path, size_t buflen)
 {
-    /* MASKED - implement this function */
+    if (path == NULL || buf == NULL || buflen == 0) {
+        return -EINVAL;
+    }
+    if (path[0] != '/') {
+        return -EINVAL;
+    }
+
+    size_t w = 0;
+    int components = 0;
+    const char *r = path;
+
+    while (*r) {
+        while (*r == '/') {
+            r++;
+        }
+        if (*r == '\0') {
+            break;
+        }
+
+        const char *start = r;
+        while (*r != '/' && *r != '\0') {
+            r++;
+        }
+        size_t len = r - start;
+
+        if (len == 1 && start[0] == '.') {
+            continue;
+        }
+        if (len == 2 && start[0] == '.' && start[1] == '.') {
+            if (components == 0) {
+                return -EINVAL;
+            }
+            components--;
+            w--;
+            while (w > 0 && buf[w - 1] != '/') {
+                w--;
+            }
+            if (w > 0) {
+                w--;
+            }
+            continue;
+        }
+
+        if (w + len + 2 > buflen) {
+            return -ENAMETOOLONG;
+        }
+        buf[w++] = '/';
+        memmove(buf + w, start, len);
+        w += len;
+        components++;
+    }
+
+    if (components == 0) {
+        if (buflen < 2) {
+            return -ENAMETOOLONG;
+        }
+        buf[0] = '/';
+        buf[1] = '\0';
+    } else {
+        buf[w] = '\0';
+    }
+
+    return components;
 }

