+    if (rb->cur_start != NULL) {
+        rb->cur = rb->cur_start;
+        if (rb->protect == rb->cur_start) {
+            rb->protect = NULL;
+        }
+    }
+
+    /* check that a free chunk slot exists */
+    unsigned idx = rb->chunk_cur;
+    bool slot_free = false;
+    for (unsigned i = 0; i < CONFIG_CHUNK_NUM_MAX; i++) {
+        if (rb->chunk_start[idx] == NULL) {
+            slot_free = true;
+            break;
+        }
+        if (++idx == CONFIG_CHUNK_NUM_MAX) {
+            idx = 0;
+        }
+    }
+    if (!slot_free) {
+        return false;
+    }
+
+    /* refuse to start if the buffer is full (cur at the protected boundary
+       with valid data present — writing would overwrite it) */
+    if (rb->protect != NULL && rb->cur == rb->protect) {
+        return false;
+    }
+
+    rb->cur_start = rb->cur;
+    return true;
